import{_ as s,c as e,a3 as i,o as t}from"./chunks/framework.VX8o9GSp.js";const c=JSON.parse('{"title":"Pull Request 的步骤","description":"","frontmatter":{"prev":false,"next":false,"date":"2024-12-01T00:00:00.000Z","tags":["git","pull request"],"categories":["计算机"]},"headers":[],"relativePath":"2024/12/pull_request_steps.md","filePath":"2024/12/pull_request_steps.md","lastUpdated":1733065311000}'),l={name:"2024/12/pull_request_steps.md"};function n(p,a,r,h,d,o){return t(),e("div",null,a[0]||(a[0]=[i(`<h1 id="pull-request-的步骤" tabindex="-1">Pull Request 的步骤 <a class="header-anchor" href="#pull-request-的步骤" aria-label="Permalink to &quot;Pull Request 的步骤&quot;">​</a></h1><p>为开源项目提 Pull Request (PR) 的步骤如下：</p><h2 id="_1-fork-仓库" tabindex="-1">1. Fork 仓库： <a class="header-anchor" href="#_1-fork-仓库" aria-label="Permalink to &quot;1. Fork 仓库：&quot;">​</a></h2><p>前往你要贡献的开源项目仓库，点击右上角的 &quot;Fork&quot; 按钮，这将创建该仓库的副本到你的 GitHub 账户下。</p><h2 id="_2-克隆仓库" tabindex="-1">2. 克隆仓库： <a class="header-anchor" href="#_2-克隆仓库" aria-label="Permalink to &quot;2. 克隆仓库：&quot;">​</a></h2><p>在你的本地机器上克隆你 Fork 的仓库。例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/你的用户名/仓库名.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后进入克隆的仓库目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 仓库名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_3-创建新分支" tabindex="-1">3. 创建新分支： <a class="header-anchor" href="#_3-创建新分支" aria-label="Permalink to &quot;3. 创建新分支：&quot;">​</a></h2><p>创建一个分支以进行你的更改，并切换到该分支。例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 新分支名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_4-进行更改" tabindex="-1">4. 进行更改： <a class="header-anchor" href="#_4-进行更改" aria-label="Permalink to &quot;4. 进行更改：&quot;">​</a></h2><p>在你的本地仓库中进行代码更改。确保遵循项目的代码规范和贡献指南。</p><h2 id="_5-提交更改" tabindex="-1">5. 提交更改： <a class="header-anchor" href="#_5-提交更改" aria-label="Permalink to &quot;5. 提交更改：&quot;">​</a></h2><p>将你的更改添加并提交到新分支中。例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;简要描述你的更改&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="_6-推送到-github" tabindex="-1">6. 推送到 GitHub： <a class="header-anchor" href="#_6-推送到-github" aria-label="Permalink to &quot;6. 推送到 GitHub：&quot;">​</a></h2><p>将你的更改推送到你的 Fork 仓库中。例如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 新分支名</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_7-创建-pull-request" tabindex="-1">7. 创建 Pull Request： <a class="header-anchor" href="#_7-创建-pull-request" aria-label="Permalink to &quot;7. 创建 Pull Request：&quot;">​</a></h2><p>前往原始仓库的 GitHub 页面，你会看到一个提示，询问你是否要为你刚刚推送的分支创建 Pull Request。点击 &quot;Compare &amp; pull request&quot; 按钮，填写 PR 的标题和描述，然后点击 &quot;Create pull request&quot;。</p><h2 id="_8-与维护者沟通" tabindex="-1">8. 与维护者沟通： <a class="header-anchor" href="#_8-与维护者沟通" aria-label="Permalink to &quot;8. 与维护者沟通：&quot;">​</a></h2><p>PR 提交后，项目维护者可能会对你的更改进行审查，并要求你做出一些修订。保持沟通，及时响应审查意见。</p><h2 id="_9-合并-pr" tabindex="-1">9. 合并 PR： <a class="header-anchor" href="#_9-合并-pr" aria-label="Permalink to &quot;9. 合并 PR：&quot;">​</a></h2><p>如果你的更改通过了审查，维护者将会合并你的 PR。你的贡献将被包含在项目中。</p><p>通过以上步骤，你就可以为开源项目贡献代码了。</p>`,27)]))}const k=s(l,[["render",n]]);export{c as __pageData,k as default};
